const message = {
  token: recipientToken,
  notification: {
    title: 'CanlıPazardan bir mesajınız var',
    body: text.substring(0, 100)
  },
  data: {
    type: 'message',
    senderId: senderId,
    receiverId: recipientId,
    messageId: messageId,
    text: text,
    unreadCount: unreadCount.toString()
  },
  apns: {
    payload: {
      aps: {
        sound: 'default',
        badge: unreadCount,
        'content-available': 1,
        alert: {
          title: 'CanlıPazardan bir mesajınız var',
          body: text.substring(0, 100)
        }
      }
    },
    headers: {
      'apns-priority': '10',
      'apns-push-type': 'alert'
    }
  }
};
